 1→import React, { createContext, useContext, useEffect, useState } from 'react';
 2→
 3→type Theme = 'light' | 'dark';
 4→
 5→interface ThemeContextValue {
 6→  theme: Theme;
 7→  toggleTheme: () => void;
 8→}
 9→
10→const ThemeContext = createContext<ThemeContextValue>({
11→  theme: 'light',
12→  toggleTheme: () => {},
13→});
14→
15→export function ThemeProvider({ children }: { children: React.ReactNode }) {
16→  const [theme, setTheme] = useState<Theme>(() => {
17→    if (typeof window !== 'undefined') {
18→      const stored = localStorage.getItem('stan-theme') as Theme | null;
19→      if (stored) return stored;
20→      return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
21→    }
22→    return 'light';
23→  });
24→
25→  useEffect(() => {
26→    const root = document.documentElement;
27→    if (theme === 'dark') {
28→      root.classList.add('dark');
29→    } else {
30→      root.classList.remove('dark');
31→    }
32→    localStorage.setItem('stan-theme', theme);
33→  }, [theme]);
34→
35→  const toggleTheme = () => setTheme(prev => (prev === 'dark' ? 'light' : 'dark'));
36→
37→  return (
38→    <ThemeContext.Provider value={{ theme, toggleTheme }}>
39→      {children}
40→    </ThemeContext.Provider>
41→  );
42→}
43→
44→export function useTheme() {
45→  return useContext(ThemeContext);
46→}
