import React, { useState } from 'react';
import {
  CreditCard,
  Wallet,
  Calendar,
  Mail,
  BarChart,
  Zap,
  Plug,
} from 'lucide-react';
import { Card } from '../components/ui/Card';
import { Button } from '../components/ui/Button';
import { Badge } from '../components/ui/Badge';
import { Tabs } from '../components/ui/Tabs';
import { demoIntegrations } from '../lib/demo-data';
import type { Integration } from '../types';

const ICON_MAP: Record<string, React.ElementType> = {
  CreditCard,
  Wallet,
  Calendar,
  Mail,
  BarChart,
  Zap,
};

const FILTER_TABS = [
  { id: 'all', label: 'All' },
  { id: 'payment', label: 'Payment' },
  { id: 'calendar', label: 'Calendar' },
  { id: 'email', label: 'Email' },
  { id: 'analytics', label: 'Analytics' },
];

export default function Integrations() {
  const [activeFilter, setActiveFilter] = useState('all');
  const [integrations, setIntegrations] = useState<Integration[]>(demoIntegrations);

  const filtered =
    activeFilter === 'all'
      ? integrations
      : integrations.filter((i) => i.type === activeFilter);

  const handleToggleConnection = (id: string) => {
    setIntegrations((prev) =>
      prev.map((i) =>
        i.id === id ? { ...i, connected: !i.connected } : i,
      ),
    );
  };

  return (
    <div className="page-enter space-y-6">
      {/* Header */}
      <div>
        <h1 className="text-2xl font-bold text-[var(--text-primary)]">
          Integrations
        </h1>
        <p className="text-[var(--text-secondary)] mt-1">
          Connect your favorite tools to extend your store's capabilities
        </p>
      </div>

      {/* Filter Tabs */}
      <Tabs tabs={FILTER_TABS} activeTab={activeFilter} onChange={setActiveFilter} />

      {/* Integration Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {filtered.map((integration) => {
          const IconComponent = ICON_MAP[integration.icon] || Plug;

          return (
            <Card key={integration.id} padding="md" hover>
              <div className="flex items-start gap-4">
                {/* Icon */}
                <div
                  className={`w-12 h-12 rounded-xl flex items-center justify-center shrink-0 ${
                    integration.connected
                      ? 'bg-emerald-500/10'
                      : 'bg-[var(--bg-elevated)]'
                  }`}
                >
                  <IconComponent
                    className={`w-6 h-6 ${
                      integration.connected
                        ? 'text-emerald-600 dark:text-emerald-400'
                        : 'text-[var(--text-secondary)]'
                    }`}
                  />
                </div>

                {/* Content */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="text-sm font-semibold text-[var(--text-primary)]">
                      {integration.name}
                    </h3>
                    <Badge variant={integration.connected ? 'success' : 'default'}>
                      {integration.connected ? 'Connected' : 'Not Connected'}
                    </Badge>
                  </div>
                  <p className="text-sm text-[var(--text-secondary)] mb-3">
                    {integration.description}
                  </p>
                  <Button
                    variant={integration.connected ? 'danger' : 'primary'}
                    size="sm"
                    onClick={() => handleToggleConnection(integration.id)}
                  >
                    {integration.connected ? 'Disconnect' : 'Connect'}
                  </Button>
                </div>
              </div>
            </Card>
          );
        })}
      </div>

      {filtered.length === 0 && (
        <div className="text-center py-12">
          <Plug className="w-10 h-10 text-[var(--text-tertiary)] mx-auto mb-3" />
          <p className="text-sm text-[var(--text-secondary)]">
            No integrations found for this category.
          </p>
        </div>
      )}
    </div>
  );
}

import React, { useState, Suspense, lazy } from 'react';
import { ThemeProvider } from './lib/theme-context';
import AppShell from './components/layout/AppShell';
import { demoUser } from './lib/demo-data';

// Lazy-load all page components
const Dashboard = lazy(() => import('./pages/Dashboard'));
const MyStore = lazy(() => import('./pages/MyStore'));
const AllProducts = lazy(() => import('./pages/AllProducts'));
const DigitalProducts = lazy(() => import('./pages/DigitalProducts'));
const Courses = lazy(() => import('./pages/Courses'));
const Bookings = lazy(() => import('./pages/Bookings'));
const Memberships = lazy(() => import('./pages/Memberships'));
const Orders = lazy(() => import('./pages/Orders'));
const Subscribers = lazy(() => import('./pages/Subscribers'));
const Affiliates = lazy(() => import('./pages/Affiliates'));
const EmailFlows = lazy(() => import('./pages/EmailFlows'));
const Broadcasts = lazy(() => import('./pages/Broadcasts'));
const DiscountCodes = lazy(() => import('./pages/DiscountCodes'));
const AnalyticsOverview = lazy(() => import('./pages/AnalyticsOverview'));
const TrafficSources = lazy(() => import('./pages/TrafficSources'));
const StoreSettings = lazy(() => import('./pages/StoreSettings'));
const Integrations = lazy(() => import('./pages/Integrations'));
const PaymentSetup = lazy(() => import('./pages/PaymentSetup'));
const Account = lazy(() => import('./pages/Account'));

// Page ID to component mapping
const PAGE_MAP: Record<string, React.LazyExoticComponent<React.ComponentType<any>>> = {
  'dashboard': Dashboard,
  'my-store': MyStore,
  'all-products': AllProducts,
  'digital-products': DigitalProducts,
  'courses': Courses,
  'bookings': Bookings,
  'memberships': Memberships,
  'orders': Orders,
  'subscribers': Subscribers,
  'affiliates': Affiliates,
  'email-flows': EmailFlows,
  'broadcasts': Broadcasts,
  'discount-codes': DiscountCodes,
  'analytics-overview': AnalyticsOverview,
  'traffic-sources': TrafficSources,
  'store-settings': StoreSettings,
  'integrations': Integrations,
  'payment-setup': PaymentSetup,
  'account': Account,
};

// Loading spinner fallback
function LoadingSpinner() {
  return (
    <div className="flex items-center justify-center h-64">
      <div
        className="w-8 h-8 border-3 border-[var(--border-default)] border-t-[var(--accent)] rounded-full animate-spin"
        style={{ borderWidth: '3px' }}
      />
    </div>
  );
}

export default function App() {
  const [currentView, setCurrentView] = useState('dashboard');

  const ActivePage = PAGE_MAP[currentView] || Dashboard;

  return (
    <ThemeProvider>
      <AppShell
        activePage={currentView}
        onPageChange={setCurrentView}
        user={{ name: demoUser.name, avatar: demoUser.avatar }}
        plan={demoUser.plan}
      >
        <Suspense fallback={<LoadingSpinner />}>
          <ActivePage />
        </Suspense>
      </AppShell>
    </ThemeProvider>
  );
}
